21. 
22. export type oidcContext = {
23.   (name?: string): OidcClient;
24. };
25. 
26. const defaultEventState = { name: '', data: null };
27. 
28. export type OidcProviderProps = {
29.   callbackSuccessComponent?: ComponentType<any>;
30.   sessionLostComponent?: ComponentType<any>;
31.   authenticatingComponent?: ComponentType<any>;
32.   authenticatingErrorComponent?: ComponentType<any>;
33.   loadingComponent?: ComponentType<any>;
34.   serviceWorkerNotSupportedComponent?: ComponentType<any>;
35.   configurationName?: string;
36.   configuration?: OidcConfiguration;
37.   children: any;
38.   onSessionLost?: () => void;
39.   onLogoutFromAnotherTab?: () => void;
40.   onLogoutFromSameTab?: () => void;
41.   withCustomHistory?: () => CustomHistory;
42.   onEvent?: (configuration: string, name: string, data: any) => void;
43.   getFetch?: () => Fetch;
44.   location?: ILOidcLocation;
45. };
46. 
47. export type OidcSessionProps = {
48.   configurationName: string;
49.   loadingComponent: PropsWithChildren<any>;
50. };
51. 
52. const OidcSession: FC<PropsWithChildren<OidcSessionProps>> = ({
53.   loadingComponent,
54.   children,
55.   configurationName,
56. }) => {
57.   const [isLoading, setIsLoading] = useState(true);
58.   const getOidc = OidcClient.get;
59.   const oidc = getOidc(configurationName);
60.   useEffect(() => {
61.     let isMounted = true;
62.     if (oidc) {
63.       oidc.tryKeepExistingSessionAsync().then(() => {
64.         if (isMounted) {
65.           setIsLoading(false);
66.         }
67.       });
68.     }
69.     return () => {
70.       isMounted = false;
71.     };
72.   }, [configurationName]);
73.   const LoadingComponent = loadingComponent;
74.   return (
75.     <>{isLoading ? <LoadingComponent configurationName={configurationName} /> : <>{children}</>}</>
76.   );
77. };
78. 
79. const Switch = ({ isLoading, loadingComponent, children, configurationName }) => {
80.   const LoadingComponent = loadingComponent;
81.   if (isLoading) {
82.     return <LoadingComponent configurationName={configurationName}>{children}</LoadingComponent>;
83.   }
84.   return <>{children}</>;
85. };
86. 
87. export const OidcProvider: FC<PropsWithChildren<OidcProviderProps>> = ({
88.   children,
89.   configuration,
90.   configurationName = 'default',
91.   callbackSuccessComponent = CallBackSuccess,
92.   authenticatingComponent = Authenticating,
93.   loadingComponent = Loading,
94.   serviceWorkerNotSupportedComponent = ServiceWorkerNotSupported,
95.   authenticatingErrorComponent = AuthenticatingError,
96.   sessionLostComponent = SessionLost,
97.   onSessionLost = null,
98.   onLogoutFromAnotherTab = null,
99.   onLogoutFromSameTab = null,
100.   withCustomHistory = null,
101.   onEvent = null,
102.   getFetch = null,
103.   location = null,
104. }) => {
105.   if (configuration && configuration.redirect_uri && configuration.silent_redirect_uri) {
106.     if (configuration.redirect_uri === configuration.silent_redirect_uri) {
107.       throw new Error('redirect_uri and silent_redirect_uri must be different');
108.     }
109.   }
110. 
111.   const getOidc = (configurationName = 'default') => {
112.     return OidcClient.getOrCreate(getFetch ?? getFetchDefault, location ?? new OidcLocation())(
113.       configuration,
114.       configurationName,
115.     );
116.   };
117. 
118.   const loading = false;
119.   const [event, setEvent] = useState(defaultEventState);
120.   const [currentConfigurationName, setConfigurationName] = useState(configurationName);
121. 
122.   useEffect(() => {
123.     const oidc = getOidc(configurationName);
124.     const newSubscriptionId = oidc.subscribeEvents((name, data) => {
125.       if (onEvent) {
126.         onEvent(configurationName, name, data);
127.       }
128.     });
129.     return () => {
130.       const previousOidc = getOidc(configurationName);
